from mcp.server.fastmcp import FastMCP

# Step 1: create the server with a name
mcp = FastMCP("team-glossary")

# Step 2: register a tool — an ordinary function
@mcp.tool()
def define_term(term: str) -> str:
    """Returns the definition of a term from the team glossary.
    Use when the user asks the meaning of an internal term."""
    glossary = {
        "SLA": "Service Level Agreement",
        "MRR": "Monthly Recurring Revenue",
    }
    return glossary.get(term, f"The term \"{term}\" is not in the glossary")

# Step 3: launch the stdio transport
mcp.run()

